  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="alert-dialog-header"
      className={cn("cn-alert-dialog-header", className)}
      {...props}
    />
  )
}
```

---

### 3. TypeScript Patterns

All components follow consistent TypeScript patterns:

```typescript
