// 5. Preserve className handling with cn() utility
```

---

### 4. Data-Slot Pattern

**Every component uses `data-slot` attributes** for CSS targeting and styling hooks:

```typescript
<ComponentPrimitive.Root
  data-slot="component-name"
  className={cn("cn-component-name", className)}
  {...props}
/>
```

Benefits:
- Semantic way to target components in CSS
- Doesn't rely on brittle class selectors
- Easy to style with `[data-slot="..."]` selectors
- Consistent naming: `data-slot="parent-child"` (kebab-case)

---

### 5. CVA (class-variance-authority) Usage

Used in components with multiple styling variants:

```typescript
import { cva, type VariantProps } from "class-variance-authority"

const componentVariants = cva("base-classes", {
  variants: {
    variant: {
      default: "variant-default-classes",
      outline: "variant-outline-classes",
    },
    size: {
      default: "size-default-classes",
      sm: "size-sm-classes",
    },
  },
  defaultVariants: {
    variant: "default",
    size: "default",
  },
})

function Component({
  className,
  variant = "default",
  size = "default",
  ...props
}: React.ComponentProps<...> & VariantProps<typeof componentVariants>) {
  return (
    <div
      className={cn(componentVariants({ variant, size }), className)}
      {...props}
    />
  )
}

export { Component, componentVariants }
```

---

### 6. Export Patterns

**Named Exports Only** - No dot notation (e.g., `Accordion.Root`):

```typescript
// YES - Named exports
export { Accordion, AccordionItem, AccordionTrigger, AccordionContent }

// NOT used in this codebase
// NO - Dot notation like Accordion.Root
```

When exporting CVA variants or custom hooks:

```typescript
