type StepperContextProps = {
  currentStep: number
  setCurrentStep: (step: number) => void
  totalSteps: number
  orientation?: "horizontal" | "vertical"
  onStepChange?: (step: number) => void
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

export { Stepper, StepperItem, StepperTrigger, StepperContent, useStepper }
```

**Option 2: Radix Wrapper Pattern (Simple Layout)**
Use this if Stepper is just a layout/presentation component without shared state.

```typescript
// stepper.tsx
function Stepper({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper"
      className={cn("cn-stepper flex w-full", className)}
      {...props}
    />
  )
}

export { Stepper, StepperItem, StepperTrigger, StepperContent }
```

**Recommended structure:**
- Use **CVA for step variants** (active, completed, disabled, pending)
- Use **Context if steps need to talk to each other** (validation, navigation)
- Use **data-slot** attributes: `data-slot="stepper"`, `data-slot="stepper-item"`, etc.
- Consider **data-state** for step status: `data-state="active" | "completed" | "disabled"`
- Export custom hook if using context: `useStepper`
- Named exports, no dot notation

