# Plan: Add Stepper Compound Component to shadcn/ui

## Context

Multi-step wizards and onboarding flows are a common UI pattern with no existing shadcn/ui primitive. This adds a `Stepper` compound component following the exact patterns of existing components (`carousel.tsx` for context, `field.tsx` for orientation, `accordion.tsx` for simple sub-component structure). No Radix UI primitive exists for this pattern — it's built entirely from scratch with React Context and Tailwind CSS.

**Constraint**: Do NOT modify any existing component files. Only create new files and append registry entries.

---

## Files to Create (3 new files)

1. `apps/v4/registry/new-york-v4/ui/stepper.tsx`
2. `apps/v4/registry/new-york-v4/examples/stepper-demo.tsx`
3. `apps/v4/registry/new-york-v4/examples/stepper-vertical.tsx`

## Files to Modify (append entries only)

1. `apps/v4/registry/new-york-v4/ui/_registry.ts` — add `stepper` entry between `spinner` (ends ~line 563) and `switch` (~line 564)
2. `apps/v4/registry/new-york-v4/examples/_registry.ts` — add `stepper-demo` and `stepper-vertical` entries between `spinner-item` (~line 2124) and `switch-demo` (~line 2125)

---

## Component Architecture

### Two React Contexts

```ts
// Root context — shared across all sub-components
type StepperContextProps = {
  value: string
  onValueChange: (value: string) => void
  orientation: "horizontal" | "vertical"
}

// Per-item context — shared between Trigger, Indicator, Title, Description, Content
type StepperItemContextProps = {
  value: string
  disabled: boolean
  completed: boolean
}
```

### State Derivation Helper (reduces duplication)

```ts
function deriveStepState(
  activeValue: string, itemValue: string,
  disabled: boolean, completed: boolean
): "active" | "completed" | "pending" | "disabled" {
  if (disabled) return "disabled"
  if (activeValue === itemValue) return "active"
  if (completed) return "completed"
  return "pending"
}
```

### Sub-components (8 total)

| Component | Element | Key Props | Notes |
|---|---|---|---|
| `Stepper` | `<div>` | `value`, `onValueChange`, `orientation?` | Provides `StepperContext`. `flex-row` or `flex-col` |
| `StepperItem` | `<div>` | `value`, `disabled?`, `completed?` | Provides `StepperItemContext`. Sets `data-state` |
| `StepperTrigger` | `<button>` | — | Calls `onValueChange` on click. Sets `aria-current="step"` when active |
| `StepperIndicator` | `<span>` | — | Visual circle. `aria-hidden="true"`. Renders children (number or icon) |
| `StepperTitle` | `<p>` | — | Step label text. Color changes per `data-state` |
| `StepperDescription` | `<p>` | — | Secondary description. Muted color |
| `StepperSeparator` | `<div>` | — | Reads orientation from context. `h-px flex-1` (horiz) or `w-px ms-[15px]` (vert) |
| `StepperContent` | `<div>` | — | Returns `null` when step is not active. `ms-10 pb-4` for vertical alignment |

**Exported hook**: `useStepper()` — throws if used outside `<Stepper />`

---

## Step 1: Create `apps/v4/registry/new-york-v4/ui/stepper.tsx`

```tsx
"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

// ─── State Helper ──────────────────────────────────────────────────────────

function deriveStepState(
  activeValue: string,
  itemValue: string,
  disabled: boolean,
  completed: boolean
): "active" | "completed" | "pending" | "disabled" {
  if (disabled) return "disabled"
  if (activeValue === itemValue) return "active"
  if (completed) return "completed"
  return "pending"
}

// ─── Stepper Context ───────────────────────────────────────────────────────

type StepperContextProps = {
  value: string
  onValueChange: (value: string) => void
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

// ─── StepperItem Context ───────────────────────────────────────────────────

type StepperItemContextProps = {
  value: string
  disabled: boolean
  completed: boolean
}

const StepperItemContext = React.createContext<StepperItemContextProps | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// ─── Stepper ───────────────────────────────────────────────────────────────

function Stepper({
  className,
  value,
  onValueChange,
  orientation = "horizontal",
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value: string
  onValueChange: (value: string) => void
  orientation?: "horizontal" | "vertical"
}) {
  return (
    <StepperContext.Provider value={{ value, onValueChange, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal" ? "flex-row items-center" : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ─── StepperItem ───────────────────────────────────────────────────────────

function StepperItem({
  className,
  value,
  disabled = false,
  completed = false,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value: string
  disabled?: boolean
  completed?: boolean
}) {
  const { value: activeValue, orientation } = useStepper()
  const state = deriveStepState(activeValue, value, disabled, completed)

  return (
    <StepperItemContext.Provider value={{ value, disabled, completed }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-orientation={orientation}
        data-disabled={disabled || undefined}
        className={cn(
          "group/stepper-item flex flex-col",
          orientation === "horizontal" && "items-center gap-1.5",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { value: activeValue, onValueChange, orientation } = useStepper()
  const { value, disabled } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-orientation={orientation}
      aria-current={activeValue === value ? "step" : undefined}
      disabled={disabled}
      onClick={() => {
        if (!disabled) {
          onValueChange(value)
        }
      }}
      className={cn(
        "inline-flex cursor-pointer gap-2 rounded-sm outline-none",
        "focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50",
        "disabled:pointer-events-none disabled:opacity-50",
        orientation === "horizontal" ? "flex-col items-center" : "flex-row items-center",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

// ─── StepperIndicator ──────────────────────────────────────────────────────

function StepperIndicator({ className, children, ...props }: React.ComponentProps<"span">) {
  const { value: activeValue } = useStepper()
  const { value, disabled, completed } = useStepperItem()
  const state = deriveStepState(activeValue, value, disabled, completed)

  return (
    <span
      data-slot="stepper-indicator"
      data-state={state}
      aria-hidden="true"
      className={cn(
        "inline-flex size-8 shrink-0 items-center justify-center rounded-full text-xs font-medium transition-colors",
        "data-[state=active]:bg-primary data-[state=active]:text-primary-foreground",
        "data-[state=completed]:bg-primary data-[state=completed]:text-primary-foreground",
        "data-[state=pending]:border-2 data-[state=pending]:border-muted-foreground/30 data-[state=pending]:bg-background data-[state=pending]:text-muted-foreground",
