## Step 1: Create `apps/v4/registry/new-york-v4/ui/stepper.tsx`

```tsx
"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

// ─── State Helper ──────────────────────────────────────────────────────────

function deriveStepState(
  activeValue: string,
  itemValue: string,
  disabled: boolean,
  completed: boolean
): "active" | "completed" | "pending" | "disabled" {
  if (disabled) return "disabled"
  if (activeValue === itemValue) return "active"
  if (completed) return "completed"
  return "pending"
}

// ─── Stepper Context ───────────────────────────────────────────────────────

type StepperContextProps = {
  value: string
  onValueChange: (value: string) => void
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

// ─── StepperItem Context ───────────────────────────────────────────────────

type StepperItemContextProps = {
  value: string
  disabled: boolean
  completed: boolean
}

const StepperItemContext = React.createContext<StepperItemContextProps | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// ─── Stepper ───────────────────────────────────────────────────────────────

function Stepper({
  className,
  value,
  onValueChange,
  orientation = "horizontal",
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value: string
  onValueChange: (value: string) => void
  orientation?: "horizontal" | "vertical"
}) {
  return (
    <StepperContext.Provider value={{ value, onValueChange, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal" ? "flex-row items-center" : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ─── StepperItem ───────────────────────────────────────────────────────────

function StepperItem({
  className,
  value,
  disabled = false,
  completed = false,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value: string
  disabled?: boolean
  completed?: boolean
}) {
  const { value: activeValue, orientation } = useStepper()
  const state = deriveStepState(activeValue, value, disabled, completed)

  return (
    <StepperItemContext.Provider value={{ value, disabled, completed }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-orientation={orientation}
        data-disabled={disabled || undefined}
        className={cn(
          "group/stepper-item flex flex-col",
          orientation === "horizontal" && "items-center gap-1.5",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { value: activeValue, onValueChange, orientation } = useStepper()
  const { value, disabled } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-orientation={orientation}
      aria-current={activeValue === value ? "step" : undefined}
      disabled={disabled}
      onClick={() => {
        if (!disabled) {
          onValueChange(value)
        }
      }}
      className={cn(
        "inline-flex cursor-pointer gap-2 rounded-sm outline-none",
        "focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50",
        "disabled:pointer-events-none disabled:opacity-50",
        orientation === "horizontal" ? "flex-col items-center" : "flex-row items-center",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

// ─── StepperIndicator ──────────────────────────────────────────────────────

function StepperIndicator({ className, children, ...props }: React.ComponentProps<"span">) {
  const { value: activeValue } = useStepper()
  const { value, disabled, completed } = useStepperItem()
  const state = deriveStepState(activeValue, value, disabled, completed)

  return (
    <span
      data-slot="stepper-indicator"
      data-state={state}
      aria-hidden="true"
      className={cn(
        "inline-flex size-8 shrink-0 items-center justify-center rounded-full text-xs font-medium transition-colors",
        "data-[state=active]:bg-primary data-[state=active]:text-primary-foreground",
        "data-[state=completed]:bg-primary data-[state=completed]:text-primary-foreground",
        "data-[state=pending]:border-2 data-[state=pending]:border-muted-foreground/30 data-[state=pending]:bg-background data-[state=pending]:text-muted-foreground",
        "data-[state=disabled]:border-2 data-[state=disabled]:border-muted-foreground/20 data-[state=disabled]:bg-background data-[state=disabled]:text-muted-foreground/50",
        className
      )}
      {...props}
    >
      {children}
    </span>
  )
}

// ─── StepperTitle ──────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  const { value: activeValue } = useStepper()
  const { value, disabled, completed } = useStepperItem()
  const state = deriveStepState(activeValue, value, disabled, completed)

  return (
    <p
      data-slot="stepper-title"
      data-state={state}
      className={cn(
        "text-sm leading-snug transition-colors",
        "data-[state=active]:font-medium data-[state=active]:text-foreground",
        "data-[state=completed]:text-foreground",
        "data-[state=pending]:text-muted-foreground",
        "data-[state=disabled]:text-muted-foreground/50",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperDescription ────────────────────────────────────────────────────

function StepperDescription({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn(
        "text-xs leading-normal text-muted-foreground",
        "group-data-[state=disabled]/stepper-item:opacity-50",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperSeparator ──────────────────────────────────────────────────────

function StepperSeparator({ className, ...props }: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      aria-hidden="true"
      className={cn(
        "shrink-0 bg-border",
        "data-[orientation=horizontal]:h-px data-[orientation=horizontal]:min-w-4 data-[orientation=horizontal]:flex-1 data-[orientation=horizontal]:self-center",
        "data-[orientation=vertical]:ms-[15px] data-[orientation=vertical]:min-h-4 data-[orientation=vertical]:w-px data-[orientation=vertical]:self-stretch",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperContent ────────────────────────────────────────────────────────

function StepperContent({ className, children, ...props }: React.ComponentProps<"div">) {
  const { value: activeValue } = useStepper()
  const { value, disabled, completed } = useStepperItem()
  const state = deriveStepState(activeValue, value, disabled, completed)

  if (state !== "active") {
    return null
  }

  return (
    <div
      data-slot="stepper-content"
      data-state={state}
      className={cn("ms-10 pb-4 text-sm", className)}
      {...props}
    >
      {children}
    </div>
  )
}

// ─── Exports ───────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperIndicator,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
}
```

