## Step 2: Create `apps/v4/registry/new-york-v4/examples/stepper-demo.tsx`

Horizontal demo with 3 steps, local state, and `CheckIcon` for completed steps.

```tsx
"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import {
  Stepper,
  StepperIndicator,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  { value: "account", label: "Account" },
  { value: "profile", label: "Profile" },
  { value: "review", label: "Review" },
]

export default function StepperDemo() {
  const [step, setStep] = React.useState("account")
  const currentIndex = steps.findIndex((s) => s.value === step)

  return (
    <Stepper value={step} onValueChange={setStep} className="w-full max-w-md">
      {steps.map((s, index) => (
        <React.Fragment key={s.value}>
          <StepperItem value={s.value} completed={currentIndex > index}>
            <StepperTrigger>
              <StepperIndicator>
                {currentIndex > index ? <CheckIcon className="size-4" /> : index + 1}
              </StepperIndicator>
              <StepperTitle>{s.label}</StepperTitle>
            </StepperTrigger>
          </StepperItem>
          {index < steps.length - 1 && <StepperSeparator />}
        </React.Fragment>
      ))}
    </Stepper>
  )
}
```

