## Step 3: Create `apps/v4/registry/new-york-v4/examples/stepper-vertical.tsx`

Vertical demo with content panels, Back/Continue navigation, and `StepperDescription`.

```tsx
"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperIndicator,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    value: "step-1",
    title: "Create your account",
    description: "Enter your email and password",
    content: "Provide a valid email address and a secure password to get started with your account.",
  },
  {
    value: "step-2",
    title: "Verify your email",
    description: "Check your inbox for a link",
    content: "We sent a verification link to your email address. Click it to confirm and continue.",
  },
  {
    value: "step-3",
    title: "Complete your profile",
    description: "Add your name and details",
    content: "Fill in your name, bio, and profile picture to personalize your account.",
  },
]

export default function StepperVertical() {
  const [step, setStep] = React.useState("step-1")
  const currentIndex = steps.findIndex((s) => s.value === step)

  function handleNext() {
    const next = steps[currentIndex + 1]
    if (next) setStep(next.value)
  }

  function handleBack() {
    const prev = steps[currentIndex - 1]
    if (prev) setStep(prev.value)
  }

  return (
    <Stepper
      value={step}
      onValueChange={setStep}
      orientation="vertical"
      className="w-full max-w-xs"
    >
      {steps.map((s, index) => (
        <StepperItem key={s.value} value={s.value} completed={currentIndex > index}>
          <StepperTrigger>
            <StepperIndicator>
              {currentIndex > index ? <CheckIcon className="size-4" /> : index + 1}
            </StepperIndicator>
            <div>
              <StepperTitle>{s.title}</StepperTitle>
              <StepperDescription>{s.description}</StepperDescription>
            </div>
          </StepperTrigger>
          {index < steps.length - 1 && <StepperSeparator />}
          <StepperContent>
            <p className="text-muted-foreground">{s.content}</p>
            <div className="mt-4 flex gap-2">
              {currentIndex > 0 && (
                <Button variant="outline" size="sm" onClick={handleBack}>
                  Back
                </Button>
              )}
              {currentIndex < steps.length - 1 && (
                <Button size="sm" onClick={handleNext}>
                  Continue
                </Button>
              )}
            </div>
          </StepperContent>
        </StepperItem>
      ))}
    </Stepper>
  )
}
