"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

// ---------------------------------------------------------------------------
// Context
// ---------------------------------------------------------------------------

type StepperContextProps = {
  value: string
  onValueChange: (value: string) => void
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

type StepperItemContextProps = {
  value: string
  disabled: boolean
  completed: boolean
}

const StepperItemContext =
  React.createContext<StepperItemContextProps | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// ---------------------------------------------------------------------------
// Stepper (root)
// ---------------------------------------------------------------------------

type StepperProps = React.ComponentProps<"div"> & {
  value: string
  onValueChange?: (value: string) => void
  orientation?: "horizontal" | "vertical"
}

function Stepper({
  value,
  onValueChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: StepperProps) {
  return (
    <StepperContext.Provider
      value={{
        value,
        onValueChange: onValueChange ?? (() => {}),
        orientation,
      }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal"
            ? "flex-row items-start"
            : "flex-col items-stretch",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperItem
// ---------------------------------------------------------------------------

type StepperItemProps = React.ComponentProps<"div"> & {
  value: string
  disabled?: boolean
  completed?: boolean
}

function StepperItem({
  value,
  disabled = false,
  completed = false,
  className,
  children,
  ...props
}: StepperItemProps) {
  const { value: activeValue, orientation } = useStepper()
  const isActive = activeValue === value

  const state = disabled
    ? "disabled"
    : completed
      ? "completed"
      : isActive
        ? "active"
        : "pending"

  return (
    <StepperItemContext.Provider value={{ value, disabled, completed }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-orientation={orientation}
        className={cn(
          "group/stepper-item flex",
          orientation === "horizontal"
            ? "flex-1 flex-col items-center"
            : "flex-col items-stretch",
          className
        )}
