"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperIndicator,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    value: "account",
    title: "Account",
    description: "Enter your email and password",
    content:
      "Provide a valid email address and choose a strong password to secure your account.",
  },
  {
    value: "profile",
    title: "Profile",
    description: "Tell us about yourself",
    content:
      "Add your name, avatar, and a short bio so others can get to know you.",
  },
  {
    value: "review",
    title: "Review",
    description: "Confirm your details",
    content:
      "Review all the information you have entered before submitting. You can go back to make changes.",
  },
]

export default function StepperVertical() {
  const [activeStep, setActiveStep] = React.useState("account")
  const activeIndex = steps.findIndex((s) => s.value === activeStep)

  return (
    <div className="w-full max-w-sm space-y-6 px-4">
      <Stepper
        value={activeStep}
        onValueChange={setActiveStep}
        orientation="vertical"
      >
        {steps.map((step, index) => (
          <StepperItem
            key={step.value}
            value={step.value}
            completed={index < activeIndex}
          >
            <StepperTrigger>
              <StepperIndicator>
                {index < activeIndex ? (
                  <CheckIcon className="size-4" />
                ) : (
                  index + 1
                )}
              </StepperIndicator>
              <div className="text-left">
                <StepperTitle>{step.title}</StepperTitle>
                <StepperDescription>{step.description}</StepperDescription>
              </div>
            </StepperTrigger>

            <StepperContent>
              <p className="text-sm text-muted-foreground">{step.content}</p>
              <div className="mt-4 flex gap-2">
                <button
                  type="button"
                  className="rounded-md border px-3 py-1.5 text-sm font-medium disabled:opacity-50"
                  disabled={activeIndex === 0}
                  onClick={() =>
                    setActiveStep(steps[activeIndex - 1]?.value ?? activeStep)
                  }
                >
                  Back
                </button>
                <button
                  type="button"
                  className="rounded-md bg-primary px-3 py-1.5 text-sm font-medium text-primary-foreground disabled:opacity-50"
                  disabled={activeIndex === steps.length - 1}
                  onClick={() =>
                    setActiveStep(steps[activeIndex + 1]?.value ?? activeStep)
                  }
                >
                  Continue
                </button>
              </div>
            </StepperContent>

            {index < steps.length - 1 && <StepperSeparator />}
          </StepperItem>
        ))}
      </Stepper>
    </div>
  )
}

